import React from 'react';
import { useTable } from 'react-table';

function ProjectOutflowsTable({ projectId, outflows }) {
  console.log('projectid', projectId);
  console.log('outs', outflows);

  // Filter the outflows based on the projectID
  const filteredOutflows = outflows.filter((out) => out.project === projectId);

  const columns = React.useMemo(
    () => [
      { Header: 'Outflow ID', accessor: 'outflowid' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'materialid' },
      { Header: 'Width', accessor: 'width' },
      { Header: 'Lot Number', accessor: 'lotnumber' },
      { Header: 'Quantity', accessor: 'quantity' },
      { Header: 'Date', accessor: 'date' },
      { Header: 'Cost', accessor: 'cost' },
      { Header: 'Employee', accessor: 'employee' },
    ],
    []
  );

  // Create an instance of the useTable hook with filtered data
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
  } = useTable(
    {
      columns,
      data: filteredOutflows, // Use the filtered data
    },
    []
  );

  return (
    <div>
      <h2>Outflows for Project: {projectId}</h2>
      <table {...getTableProps()}>
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps()}>{column.render('Header')}</th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()} key={row.id}>
                {row.cells.map((cell) => {
                  return <td {...cell.getCellProps()}>{cell.render('Cell')}</td>;
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default ProjectOutflowsTable;
